    init(environment: Environment) {
        self.environment = environment
    }
    
    private func makeRequest(endpoint: String, method: String, body: Data? = nil) -> URLRequest? {
        guard let url = URL(string: "\(environment.baseURL)\(endpoint)") else { return nil }
        var request = URLRequest(url: url)
        request.httpMethod = method
        if let body = body {
            request.httpBody = body
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        }
        return request
    }
    
    func fetchUserData(completion: @escaping (Result<Data, Error>) -> Void) {
        guard let request = makeRequest(endpoint: "/user", method: "GET") else { return }
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
